namespace sv_f7b4b479a60a498f8b26032a693c5dd3;

public enum Theme
{
    Light,
    Dark,
    System
}

public class ThemeInfo
{
    public Theme Theme { get; set; } = Theme.Light;
    public string AccentColor { get; set; } = "#0d6efd";
}

﻿<span class="theme-indicator" style="color: @(Theme?.AccentColor ?? "#0d6efd");">
    @ThemeLabel
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string ThemeLabel => Theme?.Theme switch
    {
        Theme.Dark => "🌙 Dark",
        Theme.System => "💻 System",
        _ => "☀️ Light"
    };
}

﻿@inject CascadingValueSource<ThemeInfo> ThemeSource
@rendermode InteractiveServer

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
        title="Current: @(Theme?.Theme)">
    @ThemeIcon
</button>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string ThemeIcon => Theme?.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    private async Task CycleTheme()
    {
        var current = Theme ?? new ThemeInfo();
        var next = current.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };

        await ThemeSource.NotifyChangedAsync(
            new ThemeInfo { Theme = next, AccentColor = current.AccentColor });
    }
}

﻿@page "/settings"
@inject CascadingValueSource<ThemeInfo> ThemeSource
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@currentTheme" @onchange="OnThemeChanged">
                <option value="Light">☀️ Light</option>
                <option value="Dark">🌙 Dark</option>
                <option value="System">💻 System</option>
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@accentColor" @onchange="OnAccentChanged" />
                <span class="text-muted">@accentColor</span>
            </div>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string currentTheme = nameof(Theme.Light);
    private string accentColor = "#0d6efd";

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            currentTheme = Theme.Theme.ToString();
            accentColor = Theme.AccentColor;
        }
    }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var parsed))
        {
            currentTheme = parsed.ToString();
            await PushUpdate();
        }
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        accentColor = e.Value?.ToString() ?? accentColor;
        await PushUpdate();
    }

    private async Task PushUpdate()
    {
        var updated = new ThemeInfo
        {
            Theme = Enum.Parse<Theme>(currentTheme),
            AccentColor = accentColor
        };
        await ThemeSource.NotifyChangedAsync(updated);
    }
}

